# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

// Define the base directory for templates
define('TEMPLATE_DIR', __DIR__ . '/templates/');

// Define allowed pages (whitelist for security)
$allowed_pages = [
    'home',
    'about',
    'contact',
    'services',
    'blog',
    'portfolio',
    'faq',
    'privacy',
    'terms',
    '404'
];

// Get the requested page from the URL parameter, default to 'home'
$page = isset($_GET['page']) ? $_GET['page'] : 'home';

// Sanitize the page parameter to prevent directory traversal attacks
$page = basename($page);
$page = preg_replace('/[^a-zA-Z0-9_-]/', '', $page);

// Validate the page against the whitelist
if (!in_array($page, $allowed_pages)) {
    $page = '404';
}

// Build the full file path
$template_file = TEMPLATE_DIR . $page . '.php';

// Check if the template file exists
if (!file_exists($template_file)) {
    $template_file = TEMPLATE_DIR . '404.php';
    
    // If even the 404 template doesn't exist, show a basic error
    if (!file_exists($template_file)) {
        http_response_code(404);
        echo '<!DOCTYPE html><html><head><title>404 - Page Not Found</title></head>';
        echo '<body><h1>404 - Page Not Found</h1>';
        echo '<p>The requested page could not be found.</p>';
        echo '<a href="?page=home">Go to Home</a>';
        echo '</body></html>';
        exit;
    }
}

// Set the appropriate HTTP response code for 404 pages
if ($page === '404') {
    http_response_code(404);
}

// Make the current page name available to templates
$current_page = $page;

// Helper function to generate navigation links
function nav_link($page_name, $label, $current_page) {
    $active = ($page_name === $current_page) ? ' class="active"' : '';
    return '<a href="?page=' . htmlspecialchars($page_name) . '"' . $active . '>' . htmlspecialchars($label) . '</a>';
}

// Helper function to safely get the page title
function page_title($page) {
    $titles = [
        'home'      => 'Home',
        'about'     => 'About Us',
        'contact'   => 'Contact',
        'services'  => 'Services',
        'blog'      => 'Blog',
        'portfolio' => 'Portfolio',
        'faq'       => 'FAQ',
        'privacy'   => 'Privacy Policy',
        'terms'     => 'Terms of Service',
        '404'       => 'Page Not Found'
    ];
    return isset($titles[$page]) ? $titles[$page] : ucfirst($page);
}

?>
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title><?php echo htmlspecialchars(page_title($current_page)); ?> - My CMS</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        header { background: #2c3e50; color: #fff; padding: 1rem 2rem; }
        header h1 { display: inline-block; margin-right: 2rem; }
        nav { display: inline-block; }
        nav a { color: #ecf0f1; text-decoration: none; margin-right: 1rem; padding: 0.5rem; }
        nav a:hover, nav a.active { color: #3498db; border-bottom: 2px solid #3498db; }
        main { max-width: 1200px; margin: 2rem auto; padding: 0 2rem; min-height: 60vh; }
        footer { background: #2c3e50; color: #ecf0f1; text-align: center; padding: 1rem; margin-top: 2rem; }
    </style>
</head>
<body>

<header>
    <h1>My CMS</h1>
    <nav>
        <?php echo nav_link('home', 'Home', $current_page); ?>
        <?php echo nav_link('about', 'About', $current_page); ?>
        <?php echo nav_link('services', 'Services', $current_page); ?>
        <?php echo nav_link('blog', 'Blog', $current_page); ?>
        <?php echo nav_link('portfolio', 'Portfolio', $current_page); ?>
        <?php echo nav_link('contact', 'Contact', $current_page); ?>
        <?php echo nav_link('faq', 'FAQ', $current_page); ?>
    </nav>
</header>

<main>
    <?php include $template_file; ?>
</main>

<footer>
    <p>&copy; <?php echo date('Y'); ?> My CMS. All rights reserved.</p>
</footer>

</body>
</html>